UPDATE products
SET metadata = metadata || '{"featured": true}'::jsonb
WHERE id = 5;

SELECT p.id, kv.key, kv.value
FROM products p,
jsonb_each_text(p.attributes) AS kv(key, value);

SELECT category, array_agg(name) AS product_list
FROM products
GROUP BY category;

SELECT id, title
FROM articles
WHERE to_tsvector('english', body) @@ to_tsquery('english', 'database & performance');

WITH RECURSIVE counter AS (
  SELECT 1 AS n
  UNION ALL
  SELECT n + 1 FROM counter WHERE n < 10
)
SELECT n FROM counter;

CREATE TABLE events (
  id BIGINT NOT NULL,
  event_date DATE NOT NULL,
  payload TEXT
) PARTITION BY RANGE (event_date);

CREATE TABLE events_2024
  PARTITION OF events
  FOR VALUES FROM ('2024-01-01') TO ('2025-01-01');

CREATE TABLE events_2025
  PARTITION OF events
  FOR VALUES FROM ('2025-01-01') TO ('2026-01-01');

CREATE TABLE orders_europe
  PARTITION OF orders
  FOR VALUES IN ('EU', 'UK');

ALTER TABLE orders
ATTACH PARTITION orders_legacy
FOR VALUES FROM ('2020-01-01') TO ('2023-01-01');

ALTER TABLE documents ENABLE ROW LEVEL SECURITY;

CREATE POLICY user_isolation ON documents
FOR SELECT
USING (owner_id = current_user_id());

CREATE POLICY insert_own_docs ON documents
FOR INSERT
WITH CHECK (owner_id = current_user_id());

CREATE ROLE reporting_user;

GRANT SELECT ON orders TO reporting_user;
GRANT SELECT ON customers TO reporting_user;

question:
A developer created an RLS policy but reports that the table owner can still see all rows despite the policy. Find what is missing and write the fix.

ALTER TABLE messages ENABLE ROW LEVEL SECURITY;

CREATE POLICY owner_only ON messages
FOR SELECT
USING (sender_id = current_user_id());

