CREATE EXTENSION IF NOT EXISTS pg_trgm;

SELECT name, similarity(name, 'Wiget') AS sim
FROM products
WHERE similarity(name, 'Wiget') > 0.3
ORDER BY sim DESC;

CREATE INDEX idx_products_tags ON products USING GIN (tags);

CREATE INDEX idx_products_attributes ON products USING GIN (attributes);

CREATE INDEX idx_products_name_trgm ON products USING GIST (name gist_trgm_ops);

CREATE SEQUENCE invoice_seq
  START 1000
  INCREMENT BY 1;

SELECT nextval('invoice_seq');

question:
The query below is supposed to find all users who have the tag 'admin' in their tags array, but it returns an error. Find and fix the bug.

SELECT id, name FROM users
WHERE tags = 'admin';

The following partitioned table definition fails. Find and fix the bug.

CREATE TABLE logs (
  id BIGINT PRIMARY KEY,
  logged_at TIMESTAMP NOT NULL,
  message TEXT
) PARTITION BY RANGE (logged_at);

answer:
CREATE TABLE logs (
  id BIGINT NOT NULL,
  logged_at TIMESTAMP NOT NULL,
  message TEXT
) PARTITION BY RANGE (logged_at);

WITH high_value AS (
  SELECT id, total FROM orders WHERE total > 1000
)
SELECT * FROM high_value;

SELECT name, department, salary,
  ROW_NUMBER() OVER (PARTITION BY department ORDER BY salary DESC) AS dept_rank
FROM employees;

SELECT id, amount,
  amount - LAG(amount) OVER (ORDER BY id) AS amount_diff
FROM sales;

SELECT name, category, price,
  MAX(price) OVER (PARTITION BY category) AS category_max
FROM products;

SELECT name, salary,
  NTILE(4) OVER (ORDER BY salary DESC) AS quartile
FROM employees;

SELECT p.id, p.name
FROM products p
WHERE NOT EXISTS (
  SELECT 1 FROM order_items oi WHERE oi.product_id = p.id
);

question:
Complete the query to delete all customers who have no orders:

DELETE FROM customers
WHERE ___ EXISTS (
  SELECT 1 FROM orders WHERE orders.customer_id = customers.id
);

answer:
DELETE FROM customers
WHERE NOT EXISTS (
  SELECT 1 FROM orders WHERE orders.customer_id = customers.id
);

SELECT email FROM customers
UNION ALL
SELECT email FROM staff;

SELECT id FROM products
EXCEPT
SELECT product_id FROM order_items;

