SAVEPOINT before_transfer;

UPDATE accounts SET balance = balance - 500 WHERE id = 1;
UPDATE accounts SET balance = balance + 500 WHERE id = 2;

COMMIT;

question:
Consider this sequence of SQL statements:

BEGIN;
UPDATE accounts SET balance = balance - 200 WHERE id = 1;
SAVEPOINT sp1;
UPDATE accounts SET balance = balance - 300 WHERE id = 1;
ROLLBACK TO sp1;
COMMIT;

If the starting balance of account id 1 is 1000, what is the final committed balance?

answer:
CREATE TABLE users (
  id SERIAL PRIMARY KEY,
  username VARCHAR(50) NOT NULL UNIQUE,
  email VARCHAR(255) NOT NULL UNIQUE,
  created_at TIMESTAMP NOT NULL DEFAULT NOW()
);

CREATE TABLE posts (
  id SERIAL PRIMARY KEY,
  user_id INT NOT NULL REFERENCES users(id),
  title VARCHAR(255) NOT NULL,
  body TEXT NOT NULL,
  published_at TIMESTAMP
);

CREATE TABLE comments (
  id SERIAL PRIMARY KEY,
  post_id INT NOT NULL REFERENCES posts(id),
  user_id INT NOT NULL REFERENCES users(id),
  body TEXT NOT NULL,
  created_at TIMESTAMP NOT NULL DEFAULT NOW()
);

CREATE TABLE students (
  id SERIAL PRIMARY KEY,
  name VARCHAR(100) NOT NULL
);

CREATE TABLE courses (
  id SERIAL PRIMARY KEY,
  title VARCHAR(200) NOT NULL
);

CREATE TABLE enrollments (
  student_id INT NOT NULL REFERENCES students(id),
  course_id INT NOT NULL REFERENCES courses(id),
  enrolled_at TIMESTAMP NOT NULL DEFAULT NOW(),
  PRIMARY KEY (student_id, course_id)
);

CREATE OR REPLACE FUNCTION set_updated_at()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_updated_at
BEFORE UPDATE ON employees
FOR EACH ROW
EXECUTE FUNCTION set_updated_at();

CREATE TABLE products (
  id SERIAL PRIMARY KEY,
  name VARCHAR(200) NOT NULL
);

CREATE TABLE product_variants (
  id SERIAL PRIMARY KEY,
  product_id INT NOT NULL REFERENCES products(id),
  sku VARCHAR(50) NOT NULL UNIQUE,
  size VARCHAR(20),
  color VARCHAR(50),
  price NUMERIC(10,2) NOT NULL
);

SELECT p.name,
  (SELECT COUNT(*) FROM order_items oi WHERE oi.product_id = p.id) AS order_count
FROM products p;

ALTER TABLE products
ADD CONSTRAINT chk_discount
CHECK (discount_price < price);

question:
The query below uses two CTEs but has a bug causing a syntax error. Find and fix it.

WITH active_users AS (
  SELECT id, name FROM users WHERE is_active = true
),
WITH recent_orders AS (
  SELECT user_id, COUNT(*) AS order_count FROM orders GROUP BY user_id
)
SELECT u.name, o.order_count
FROM active_users u
JOIN recent_orders o ON u.id = o.user_id;

answer:
WITH active_users AS (
  SELECT id, name FROM users WHERE is_active = true
),
recent_orders AS (
  SELECT user_id, COUNT(*) AS order_count FROM orders GROUP BY user_id
)
SELECT u.name, o.order_count
FROM active_users u
JOIN recent_orders o ON u.id = o.user_id;

SELECT e.name, d.dept_name
FROM employees e
FULL OUTER JOIN departments d ON e.dept_id = d.id;

SELECT e.name AS employee, m.name AS manager
FROM employees e
INNER JOIN employees m ON e.manager_id = m.id;

SELECT p.name AS product_name, s.name AS supplier_name
FROM products p
INNER JOIN suppliers s ON p.supplier_id = s.id;

