CREATE TABLE enrollments (
  id INT PRIMARY KEY,
  student_id INT NOT NULL REFERENCES students(id),
  course_id INT NOT NULL REFERENCES courses(id),
  UNIQUE (student_id, course_id)
);

CREATE TABLE employees (
  id INT PRIMARY KEY,
  name VARCHAR(100),
  dept_id INT,
  FOREIGN KEY (dept_id) REFERENCES departments(id)
);

CREATE TABLE customers (
  id INT PRIMARY KEY,
  name VARCHAR(100) NOT NULL
);

CREATE TABLE customer_phones (
  id INT PRIMARY KEY,
  customer_id INT NOT NULL REFERENCES customers(id),
  phone_number VARCHAR(20) NOT NULL
);

question:
The query below is supposed to return the names of employees who earn more than the company-wide average salary, but it returns an error. Find and fix the bug.

SELECT name FROM employees
WHERE salary > AVG(salary);

answer:
SELECT name, hire_date,
  EXTRACT(YEAR FROM AGE(NOW(), hire_date)) AS tenure_years
FROM employees;

CREATE TABLE managers (
  manager_id INT PRIMARY KEY,
  manager_name VARCHAR(100) NOT NULL
);

CREATE TABLE employees (
  employee_id INT PRIMARY KEY,
  employee_name VARCHAR(100) NOT NULL,
  manager_id INT REFERENCES managers(manager_id)
);

CREATE TABLE books (
  id INT PRIMARY KEY,
  title VARCHAR(200) NOT NULL,
  published_year INT
);
